import { useState, useRef, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ChevronDown, Menu, X, Send, Code, Smartphone, Globe, 
  BarChart3, Sprout, BrainCircuit, ShieldCheck, Leaf,
  UserPlus, Users, GraduationCap, ClipboardCheck, ArrowRight
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';

const navItems = [
  { label: 'About Us', href: '/about' },
  {
    label: 'Our Services',
    children: [
      { label: 'Web Application', href: '/services/web-application', description: 'Custom web solutions', icon: Code },
      { label: 'Mobile Application', href: '/services/mobile-application', description: 'iOS & Android apps', icon: Smartphone },
      { label: 'Digital Marketing', href: '/services/digital-marketing', description: 'Grow your brand', icon: Globe },
      { label: 'Project Management', href: '/services/project-management', description: 'Deliver on time', icon: BarChart3 },
    ],
  },
  { label: 'Career', href: '/career' },
  { label: 'Contact Us', href: '/contact' },
];

const DesktopDropdown = ({ item, isActive }: { item: any; isActive: boolean }) => {
  const [isOpen, setIsOpen] = useState(false);
  return (
    <div className="relative" onMouseEnter={() => setIsOpen(true)} onMouseLeave={() => setIsOpen(false)}>
      <button className={cn(
        "flex items-center gap-1.5 px-4 py-2 text-sm font-medium transition-all rounded-full",
        isOpen ? "text-primary bg-secondary" : "text-foreground/70 hover:text-primary",
        isActive && "text-primary font-bold"
      )}>
        {item.label}
        <ChevronDown className={cn("w-3.5 h-3.5 transition-transform", isOpen && "rotate-180")} />
      </button>
      <AnimatePresence>
        {isOpen && (
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 8 }}
            className="absolute top-full left-0 mt-2 w-64 p-2 bg-white border border-border rounded-2xl shadow-xl z-50">
            {item.children.map((child: any) => (
              <Link key={child.href} to={child.href} className="flex items-center gap-3 p-3 rounded-xl hover:bg-secondary group transition-all">
                <div className="p-2 rounded-lg bg-primary/10 text-primary group-hover:bg-primary group-hover:text-white"><child.icon className="w-4 h-4" /></div>
                <span className="text-sm font-semibold">{child.label}</span>
              </Link>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export const Navbar = () => {
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const location = useLocation();

  return (
    <div className="fixed top-0 left-0 right-0 z-[100] p-4 lg:p-6 flex justify-center">
      <motion.nav className="w-full max-w-7xl navbar-glass rounded-[2.5rem] px-6 h-16 flex items-center justify-between">
        <Link to="/" className="flex items-center gap-2 group">
          <motion.img animate={{ rotateY: 360 }} transition={{ repeat: Infinity, duration: 20 }} src="logo.png" className="w-8 h-8" />
          <span className="font-bold text-xl text-primary">Data Experts <span className="text-accent">360</span></span>
        </Link>

        <div className="hidden lg:flex items-center gap-1">
          {navItems.map((item) => item.children ? (
            <DesktopDropdown key={item.label} item={item} isActive={item.children.some(c => location.pathname === c.href)} />
          ) : (
            <Link key={item.label} to={item.href!} className={cn("px-4 py-2 text-sm font-medium transition-colors hover:text-primary", location.pathname === item.href ? "text-primary font-bold" : "text-foreground/70")}>
              {item.label}
            </Link>
          ))}
        </div>

        <div className="hidden lg:block">
          <Button asChild className="rounded-full bg-gradient-to-r from-primary to-accent text-white shadow-lg hover:shadow-primary/30 transition-all">
            <Link to="/contact" className="gap-2"><Send className="w-4 h-4" /> Request a Proposal</Link>
          </Button>
        </div>

        <button onClick={() => setIsMobileOpen(true)} className="lg:hidden p-2 text-primary"><Menu /></button>
      </motion.nav>
    </div>
  );
};